{
  "executive_summary": "Zero-downtime migration architecture for the Order Management domain from MongoDB to PostgreSQL, using a phased Strangler Fig approach with dual-write synchronization. The design introduces a Data Access Abstraction Layer to decouple application code from storage, a Change Data Capture (CDC) pipeline for historical backfill, and a Shadow Traffic Verification system to validate consistency before cutover. At 200 writes/min (~3.3/sec), the throughput is well within PostgreSQL's capabilities. The 8M document backfill is the primary risk vector and is addressed via batched background migration with checkpointing.",

  "architecture": {
    "components": [
      {
        "name": "Order Repository Abstraction",
        "responsibility": "Unified data access interface that hides the underlying storage engine. Routes reads/writes to MongoDB, PostgreSQL, or both depending on the current migration phase.",
        "boundaries": "Sits between application/service layer and storage. No business logic. All storage-specific concerns (document mapping vs relational mapping) are encapsulated in adapter implementations behind this interface."
      },
      {
        "name": "MongoDB Adapter",
        "responsibility": "Implements the repository interface against MongoDB. Existing code refactored into this adapter. Becomes read-only in Phase 3, decommissioned in Phase 5.",
        "boundaries": "Owns MongoDB connection pool, document-to-domain mapping, and MongoDB-specific query optimization."
      },
      {
        "name": "PostgreSQL Adapter",
        "responsibility": "Implements the repository interface against PostgreSQL. Handles relational mapping, transaction management, and FK constraint enforcement.",
        "boundaries": "Owns PostgreSQL connection pool, SQL query construction, and relational schema mapping. Responsible for ACID transaction boundaries across order and payment tables."
      },
      {
        "name": "Dual-Write Coordinator",
        "responsibility": "During the transition phase, ensures every write lands in both MongoDB and PostgreSQL. Treats MongoDB as primary (source of truth) and PostgreSQL as secondary. If PostgreSQL write fails, logs the failure for async retry but does NOT fail the user request.",
        "boundaries": "Activated only during Phase 2-3. Coordinates write ordering: MongoDB first (primary), then PostgreSQL. Owns retry queue for failed secondary writes."
      },
      {
        "name": "Backfill Pipeline",
        "responsibility": "Migrates the 8M historical order documents from MongoDB to PostgreSQL in batches. Uses cursor-based pagination with checkpointing to allow pause/resume. Transforms document structures to relational schema.",
        "boundaries": "Runs as a background job, isolated from production traffic. Reads from MongoDB read replicas to avoid production load. Writes to PostgreSQL with configurable batch size and throttling."
      },
      {
        "name": "Consistency Verifier",
        "responsibility": "Shadow-reads from both databases and compares results to detect drift. Reports discrepancies to an alerting system. Provides the confidence signal needed before cutover.",
        "boundaries": "Read-only against both databases. Runs as a sidecar process or scheduled job. Does not affect production latency — verification is async."
      },
      {
        "name": "Migration Phase Controller",
        "responsibility": "Feature flag system that controls which migration phase is active. Determines routing behavior of the Repository Abstraction: Phase 1 (Mongo-only), Phase 2 (dual-write, Mongo-primary), Phase 3 (dual-write, Postgres-primary), Phase 4 (Postgres-only with Mongo shadow-read), Phase 5 (Postgres-only, Mongo decommissioned).",
        "boundaries": "Configuration-driven, no business logic. Can be toggled per-environment for staged rollout. Supports instant rollback to any previous phase."
      }
    ],
    "interfaces": [
      {
        "from": "Order Service",
        "to": "Order Repository Abstraction",
        "contract": "OrderRepository interface: createOrder(order), updateOrder(id, changes), getOrder(id), queryOrders(criteria), getOrderWithPayments(id). All methods return domain objects, never storage-specific types.",
        "coupling_type": "abstraction (interface-based, zero storage coupling)"
      },
      {
        "from": "Order Repository Abstraction",
        "to": "Migration Phase Controller",
        "contract": "getPhase(): MigrationPhase enum. Queried on each operation to determine routing strategy.",
        "coupling_type": "configuration (feature flag lookup)"
      },
      {
        "from": "Order Repository Abstraction",
        "to": "Dual-Write Coordinator",
        "contract": "writeToAll(operation): Result. Coordinator returns success if primary succeeds, logs secondary failures asynchronously.",
        "coupling_type": "temporal (only active during migration phases 2-3)"
      },
      {
        "from": "Dual-Write Coordinator",
        "to": "MongoDB Adapter",
        "contract": "Standard repository write interface. Primary during Phase 2, secondary during Phase 3.",
        "coupling_type": "adapter (implements shared interface)"
      },
      {
        "from": "Dual-Write Coordinator",
        "to": "PostgreSQL Adapter",
        "contract": "Standard repository write interface. Secondary during Phase 2, primary during Phase 3.",
        "coupling_type": "adapter (implements shared interface)"
      },
      {
        "from": "Backfill Pipeline",
        "to": "MongoDB Adapter",
        "contract": "Cursor-based read: getOrdersBatch(afterCursor, batchSize). Reads from replica set.",
        "coupling_type": "data (read-only, replica-targeted)"
      },
      {
        "from": "Backfill Pipeline",
        "to": "PostgreSQL Adapter",
        "contract": "Batch upsert: upsertOrders(orders[]). Idempotent — safe to re-run on failure.",
        "coupling_type": "data (write, idempotent)"
      },
      {
        "from": "Consistency Verifier",
        "to": "Both Adapters",
        "contract": "Read-only comparison: readFromBoth(id) -> {mongo: Order, postgres: Order, match: boolean}.",
        "coupling_type": "data (read-only, non-blocking)"
      }
    ],
    "data_flow": "Phase 1 (Prepare): Application writes/reads MongoDB only. Backfill Pipeline begins copying 8M historical documents to PostgreSQL in batches of 1000, checkpointing progress. Estimated time: ~2-4 hours at throttled rate. Phase 2 (Dual-Write, Mongo Primary): Once backfill completes, activate dual-write. All writes go to MongoDB first (source of truth), then async to PostgreSQL. Reads still from MongoDB. Consistency Verifier runs continuously, sampling 5% of reads to shadow-compare. Phase 3 (Dual-Write, Postgres Primary): After consistency reaches 99.99%+, flip primary. Writes go to PostgreSQL first, then async to MongoDB. Reads from PostgreSQL. This is the critical phase — if issues arise, rollback to Phase 2 is instant via feature flag. Phase 4 (Postgres Only, Mongo Shadow): Disable MongoDB writes. Keep MongoDB read-only for 1-2 weeks as safety net. Phase 5 (Decommission): Remove MongoDB adapter, dual-write coordinator, and migration infrastructure. Clean up feature flags.",
    "patterns_used": [
      {
        "pattern": "Strangler Fig",
        "rationale": "Incrementally replaces MongoDB with PostgreSQL without big-bang cutover. Each phase is independently reversible. The service never goes down because at every phase, one database is always authoritative."
      },
      {
        "pattern": "Repository Pattern with Strategy",
        "rationale": "Abstracts storage behind an interface, with the active strategy selected by the migration phase controller. Allows the application layer to be completely unaware of the migration. After migration, the abstraction remains as good architecture."
      },
      {
        "pattern": "Dual-Write with Asymmetric Failure Handling",
        "rationale": "Primary write must succeed for the operation to succeed. Secondary write failures are logged and retried asynchronously. This preserves availability while maintaining eventual consistency during transition."
      },
      {
        "pattern": "Idempotent Backfill with Checkpointing",
        "rationale": "8M records cannot be migrated atomically. Cursor-based pagination with checkpoint storage allows pause/resume and crash recovery. Idempotent upserts make re-runs safe."
      },
      {
        "pattern": "Shadow Traffic Verification",
        "rationale": "Before trusting PostgreSQL as primary, shadow-read comparison builds empirical confidence in data consistency. This is the safety net that makes the cutover decision data-driven rather than faith-based."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root: Order entity, contains OrderLineItems as value objects, references PaymentRecord entity)",
          "PaymentRecord (root: PaymentRecord entity, linked to Order via FK in PostgreSQL)"
        ]
      },
      {
        "name": "Migration Infrastructure",
        "classification": "generic",
        "aggregates": [
          "MigrationPhase (root: PhaseConfig, tracks current phase per environment)",
          "BackfillCheckpoint (root: Checkpoint entity, tracks cursor position and batch completion)",
          "ConsistencyReport (root: Report entity, aggregates discrepancy records)"
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Migration Infrastructure",
        "relationship": "Conformist — Migration Infrastructure conforms to Order Management's domain model. It never alters the order model; it only routes and replicates it."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Dual-write with async secondary instead of CDC-based replication",
      "gains": "Simpler to implement and reason about. No dependency on MongoDB oplog or third-party CDC tools (Debezium). Application-level dual-write gives full control over transformation logic.",
      "sacrifices": "Small window of inconsistency if secondary write fails and retry is delayed. Slightly higher write latency during dual-write phase (one additional DB write per operation). Application code is migration-aware.",
      "alternatives_considered": [
        "MongoDB Change Streams + CDC pipeline (lower application coupling but adds operational complexity of stream processing infrastructure)",
        "Debezium CDC connector (mature tooling but requires Kafka, adds significant infrastructure)",
        "pg_chameleon or similar replication tool (limited transformation capability, opaque failure modes)"
      ]
    },
    {
      "decision": "MongoDB-primary first, then flip to PostgreSQL-primary",
      "gains": "Minimizes risk. If PostgreSQL has issues during dual-write, MongoDB is still source of truth. Rollback is always available. Builds confidence incrementally.",
      "sacrifices": "Longer total migration timeline (weeks, not days). Dual-write phase has higher operational complexity.",
      "alternatives_considered": [
        "Big-bang cutover with maintenance window (faster but violates zero-downtime requirement)",
        "PostgreSQL-primary from the start (higher risk, no proven consistency before trusting new store)"
      ]
    },
    {
      "decision": "Relational schema design with normalized Order + OrderLineItems + PaymentRecords tables",
      "gains": "Leverages PostgreSQL's strengths: FK constraints prevent orphaned records, JOIN queries enable efficient reporting, ACID transactions span order+payment atomically.",
      "sacrifices": "Impedance mismatch with existing MongoDB document model. Transformation logic in backfill and adapters must flatten/normalize documents. Some queries that were simple document lookups become multi-table JOINs.",
      "alternatives_considered": [
        "PostgreSQL JSONB column preserving document structure (easier migration but wastes PostgreSQL's relational strengths — defeats the purpose of migrating)",
        "Hybrid: relational core with JSONB for flexible attributes (good compromise if order documents have highly variable schemas)"
      ]
    },
    {
      "decision": "Application-level repository abstraction over database-level routing",
      "gains": "Full control over read/write routing per phase. Transformation logic is explicit in code. Testable in isolation. Survives as good architecture post-migration.",
      "sacrifices": "Requires code changes to introduce the abstraction layer. All current direct MongoDB access must be refactored behind the interface.",
      "alternatives_considered": [
        "Database proxy (e.g., ProxySQL) for routing (transparent to app but cannot handle schema transformation)",
        "Service mesh routing (too coarse-grained for per-query routing decisions)"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Migration Phase Controller",
      "evolution_path": "Feature flag-driven phases allow instant rollback at any point. Can be extended to support per-tenant or percentage-based rollout if needed. After migration, the controller is removed — it does not become permanent infrastructure."
    },
    {
      "area": "Repository Abstraction Layer",
      "evolution_path": "Survives the migration as clean architecture. If another storage migration is ever needed, the abstraction is already in place. Can also support read replicas, caching layers, or CQRS split in the future."
    },
    {
      "area": "Backfill Pipeline batch size and throttling",
      "evolution_path": "Configurable at runtime to adapt to production load. Can be paused during peak hours and resumed during off-peak. Checkpoint system makes this safe."
    },
    {
      "area": "PostgreSQL Schema",
      "evolution_path": "Can evolve independently via standard migration tools (Flyway, Alembic, etc.) once it becomes the sole store. Adding indexes, partitioning order tables by date, or adding materialized views for reporting are all straightforward PostgreSQL operations."
    }
  ],

  "rigidity_points": [
    {
      "area": "Dual-Write Ordering (primary-first guarantee)",
      "reason": "The invariant that the primary database is ALWAYS written first cannot be violated. If this ordering breaks, you get split-brain where neither database is authoritative. This ordering is enforced in the Dual-Write Coordinator and must never be bypassed."
    },
    {
      "area": "Idempotent write operations",
      "reason": "All PostgreSQL writes during migration MUST be idempotent (upsert semantics). The retry mechanism and backfill re-runs depend on this. Non-idempotent writes would cause duplicates or constraint violations."
    },
    {
      "area": "Schema transformation correctness",
      "reason": "The MongoDB document-to-relational mapping must be verified exhaustively before Phase 2. Any transformation bug that corrupts data during dual-write is extremely expensive to fix. This mapping should be treated as critical code with extensive test coverage."
    },
    {
      "area": "Phase ordering",
      "reason": "Phases must proceed in order: 1→2→3→4→5. Skipping phases (e.g., jumping from 1 to 3) breaks consistency guarantees. Rollback can go backwards but forward progression must be sequential."
    }
  ],

  "risks": [
    {
      "risk": "Data inconsistency during dual-write phase if secondary write fails and retry queue backs up",
      "severity": "high",
      "mitigation": "Monitor retry queue depth with alerting. Set SLA: secondary writes must succeed within 30 seconds or trigger alert. If queue exceeds threshold, pause migration and investigate. Consistency Verifier provides continuous detection."
    },
    {
      "risk": "Schema transformation bugs silently corrupt data during backfill of 8M records",
      "severity": "critical",
      "mitigation": "Run backfill against a staging environment with production data snapshot first. Validate a statistically significant sample (10,000+ records) via automated comparison. Unit test every transformation path including edge cases (null fields, nested arrays, legacy formats)."
    },
    {
      "risk": "Backfill and dual-write race condition: a record is updated in MongoDB while the backfill is processing it, resulting in stale data in PostgreSQL",
      "severity": "high",
      "mitigation": "Use last-write-wins with timestamp comparison. Backfill upserts include an updatedAt check: only overwrite if the backfill record is newer than what exists in PostgreSQL. Dual-write records always have the latest timestamp and will win."
    },
    {
      "risk": "PostgreSQL performance under production load differs from expectations due to different query patterns (JOINs vs document lookups)",
      "severity": "medium",
      "mitigation": "Load test PostgreSQL with realistic query patterns before Phase 3. Use the shadow-read verification phase to measure P99 latency from PostgreSQL. Only promote to primary when latency meets SLA."
    },
    {
      "risk": "Application-level dual-write increases write latency, potentially affecting user experience",
      "severity": "medium",
      "mitigation": "Secondary write is async (fire-and-forget with retry queue). Primary write latency is unchanged. Monitor P95/P99 write latency during Phase 2. At 200 writes/min, even synchronous dual-write would add only ~2-5ms overhead."
    },
    {
      "risk": "Long migration timeline increases operational burden and risk of configuration drift",
      "severity": "medium",
      "mitigation": "Target 2-4 week total migration. Create a runbook with clear phase transition criteria and rollback procedures. Automate phase transitions via the Phase Controller API. Assign a migration owner."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Execute in 5 phases over 2-4 weeks. Phase 1 (Days 1-3): Introduce repository abstraction, refactor all direct MongoDB access behind the interface, design and deploy PostgreSQL schema, implement and test backfill pipeline. Run backfill in staging. Phase 2 (Days 4-7): Deploy backfill to production against MongoDB replicas. Once complete, activate dual-write with MongoDB primary. Run consistency verifier. Phase 3 (Days 8-14): After consistency reaches 99.99%+ for 48 hours, flip to PostgreSQL primary. Monitor closely. Phase 4 (Days 15-21): Disable MongoDB writes, keep as read-only fallback. Phase 5 (Day 22+): Remove MongoDB adapter, dual-write coordinator, migration infrastructure. Clean final state: PostgreSQL with repository abstraction.",
    "files_to_create_or_modify": [
      "src/orders/repositories/OrderRepository.interface — defines storage-agnostic repository contract",
      "src/orders/repositories/MongoOrderRepository — existing MongoDB logic refactored into adapter",
      "src/orders/repositories/PostgresOrderRepository — new adapter implementing relational storage",
      "src/orders/repositories/DualWriteCoordinator — orchestrates writes to both stores during transition",
      "src/orders/repositories/OrderRepositoryFactory — selects adapter(s) based on migration phase",
      "src/migration/MigrationPhaseController — feature flag interface for phase management",
      "src/migration/BackfillPipeline — batched, checkpointed MongoDB-to-PostgreSQL data mover",
      "src/migration/BackfillCheckpoint — tracks migration cursor position for pause/resume",
      "src/migration/ConsistencyVerifier — shadow-read comparison and discrepancy reporting",
      "src/migration/transformers/OrderDocumentToRelational — maps MongoDB document structure to relational tables",
      "db/migrations/001_create_orders_schema.sql — PostgreSQL DDL: orders, order_line_items, payment_records tables with FKs and indexes",
      "tests/migration/ — integration tests for dual-write, backfill idempotency, transformation correctness"
    ],
    "patterns_to_follow": "Repository Pattern with Strategy for storage abstraction. Strangler Fig for incremental migration. Idempotent upserts for all migration writes. Feature flags for phase control. Last-write-wins with timestamp for conflict resolution. Async retry queue for secondary write failures.",
    "pitfalls_to_avoid": [
      "DO NOT make PostgreSQL writes synchronous in the critical path during dual-write — secondary writes must be async to preserve latency",
      "DO NOT skip the consistency verification phase — cutting over without empirical proof of consistency is gambling with production data",
      "DO NOT backfill from the MongoDB primary — always read from a replica to avoid impacting production read/write performance",
      "DO NOT assume MongoDB document schemas are uniform — 8M documents likely have schema drift over time; transformation code must handle all variants",
      "DO NOT remove MongoDB until Phase 5 is fully validated — premature decommission eliminates your rollback safety net",
      "DO NOT run backfill without checkpointing — if it crashes at record 7M, you need to resume from 7M, not restart from 0",
      "DO NOT use distributed transactions (2PC) across MongoDB and PostgreSQL — the complexity and failure modes are not worth it at 200 writes/min; eventual consistency with verification is the right trade-off"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Strangler Fig is the correct migration pattern for zero-downtime database migration — this is well-established industry practice",
      "200 writes/min is low throughput — PostgreSQL handles this trivially, and dual-write overhead is negligible",
      "Repository abstraction is the right decoupling point — it survives as good architecture post-migration",
      "Phase-based rollout with feature flags provides safe, reversible progression",
      "8M records is a manageable backfill — batched at 1000/batch, this is ~8000 batches, completable in hours"
    ],
    "low_confidence_areas": [
      "Exact PostgreSQL schema design — without seeing the MongoDB document structure, the relational normalization strategy is directional, not prescriptive",
      "Transformation edge cases — schema drift in 8M MongoDB documents may surface unexpected variants that require custom handling",
      "Optimal batch size and throttling — depends on MongoDB replica capacity and PostgreSQL write throughput under production network conditions; needs empirical tuning"
    ],
    "assumptions": [
      "MongoDB documents have a reasonably consistent schema with known variants — if documents are highly polymorphic, transformation complexity increases significantly",
      "The application has a service layer that can be refactored to use a repository interface without major architectural changes",
      "PostgreSQL infrastructure (instance, networking, connection pooling) is available or can be provisioned in parallel with Phase 1",
      "MongoDB replica set is available for backfill reads to avoid production impact",
      "200 writes/min is peak, not average — if peak is significantly higher, dual-write async queue sizing needs adjustment",
      "No other services write directly to the Order Management MongoDB collection — if they do, they must also go through the dual-write coordinator or be migrated first"
    ]
  }
}

